"use client";

import { Radio as RadioPrimitive } from "@base-ui/react/radio";
import { RadioGroup as RadioGroupPrimitive } from "@base-ui/react/radio-group";
import { AnimatePresence, motion } from "motion/react";
import * as React from "react";

import { cn } from "@/lib/utils";

import { MotionConfig, useReducedMotion } from "motion/react";
import { createContext, useContext } from "react";

interface ReducedMotionProp {
  reducedMotion?: boolean;
}

const ReducedMotionOverrideContext = createContext(false);

function useResolvedReducedMotion(reducedMotion?: boolean) {
  const reducedMotionOverride = useContext(ReducedMotionOverrideContext);
  const prefersReducedMotion = useReducedMotion() ?? false;

  return Boolean(
    reducedMotion || reducedMotionOverride || prefersReducedMotion
  );
}

function ReducedMotionConfig({
  children,
  reducedMotion,
}: ReducedMotionProp & {
  children: import("react").ReactNode;
}) {
  const resolvedReducedMotion = useResolvedReducedMotion(reducedMotion);

  return (
    <MotionConfig reducedMotion={resolvedReducedMotion ? "always" : "user"}>
      {children}
    </MotionConfig>
  );
}

const lightTokens = [
  "[--background:#ffffff]",
  "[--foreground:#111111]",
  "[--primary:#111111]",
  "[--secondary:#646b75]",
  "[--surface-border:#e9edf2]",
  "[--border:#e3e7ec]",
  "[--card:#ffffff]",
  "[--card-foreground:#111111]",
  "[--muted:#f5f7fa]",
  "[--muted-foreground:#6d7480]",
  "[--accent:#f3f5f8]",
  "[--accent-foreground:#111111]",
  "[--input:#e3e7ec]",
  "[--ring:rgba(17,17,17,0.16)]",
  "[--destructive:#dc2626]",
  "[--paper:#fcfcfd]",
  "[--popover-foreground:#111111]",
  "[--brand:#0ea5e9]",
  "[--brand-soft:#bae6fd]",
  "[--shadow-soft:0_18px_38px_-24px_rgba(15,23,42,0.35)]",
];

const aliasTokens = [
  "[--color-background:var(--background)]",
  "[--color-foreground:var(--foreground)]",
  "[--color-primary:var(--primary)]",
  "[--color-secondary:var(--secondary)]",
  "[--color-border:var(--border)]",
  "[--color-card:var(--card)]",
  "[--color-card-foreground:var(--card-foreground)]",
  "[--color-muted:var(--muted)]",
  "[--color-muted-foreground:var(--muted-foreground)]",
  "[--color-accent:var(--accent)]",
  "[--color-accent-foreground:var(--accent-foreground)]",
  "[--color-input:var(--input)]",
  "[--color-ring:var(--ring)]",
  "[--color-destructive:var(--destructive)]",
  "[--color-paper:var(--paper)]",
  "[--color-popover-foreground:var(--popover-foreground)]",
  "[--color-brand:var(--brand)]",
  "[--color-brand-soft:var(--brand-soft)]",
];

const darkTokens = [
  "dark:[--background:#111111]",
  "dark:[--foreground:#f6f3ec]",
  "dark:[--primary:#f6f3ec]",
  "dark:[--secondary:#cbc6bb]",
  "dark:[--surface-border:#2a2a25]",
  "dark:[--border:#2b2a25]",
  "dark:[--card:#111111]",
  "dark:[--card-foreground:#f6f3ec]",
  "dark:[--muted:#171716]",
  "dark:[--muted-foreground:#9a958a]",
  "dark:[--accent:#1a1a18]",
  "dark:[--accent-foreground:#f6f3ec]",
  "dark:[--input:#2b2a25]",
  "dark:[--ring:rgba(246,243,236,0.18)]",
  "dark:[--destructive:#f87171]",
  "dark:[--paper:#171716]",
  "dark:[--popover-foreground:#f6f3ec]",
  "dark:[--brand:#38bdf8]",
  "dark:[--brand-soft:#0c4a6e]",
  "dark:[--shadow-soft:0_20px_44px_-28px_rgba(0,0,0,0.6)]",
];

const registryTheme = [
  ...lightTokens,
  ...aliasTokens,
  ...darkTokens,
].join(" ");

const reducedTransition = { duration: 0.12 } as const;

function getHighlightTransition(reduceMotion: boolean) {
  if (reduceMotion) {
    return reducedTransition;
  }

  return {
    type: "spring" as const,
    stiffness: 300,
    damping: 28,
    mass: 0.8,
  };
}

function getRingTransition(reduceMotion: boolean) {
  if (reduceMotion) {
    return reducedTransition;
  }

  return {
    type: "spring" as const,
    stiffness: 400,
    damping: 22,
  };
}

function getDotMotion(reduceMotion: boolean) {
  if (reduceMotion) {
    return {
      animate: { opacity: 1 },
      exit: { opacity: 0 },
      initial: { opacity: 0 },
      transition: reducedTransition,
    };
  }

  return {
    animate: { scale: 1, opacity: 1 },
    exit: { scale: 0, opacity: 0 },
    initial: { scale: 0, opacity: 0 },
    transition: {
      type: "spring" as const,
      stiffness: 500,
      damping: 25,
      delay: 0.05,
    },
  };
}

function getTextTransition(reduceMotion: boolean) {
  return reduceMotion ? reducedTransition : { duration: 0.2 };
}

function getValidSelection(options: RadioOption[], candidate?: string) {
  if (candidate === undefined) {
    return options[0]?.value;
  }

  return options.some((option) => option.value === candidate)
    ? candidate
    : options[0]?.value;
}

function setRef<T>(ref: React.Ref<T> | undefined, value: T) {
  if (typeof ref === "function") {
    ref(value);
    return;
  }

  if (ref) {
    (ref as React.MutableRefObject<T>).current = value;
  }
}

export interface RadioOption {
  value: string;
  label: string;
  description?: string;
}

export interface RadioGroupProps extends ReducedMotionProp {
  options: RadioOption[];
  defaultValue?: string;
  value?: string;
  onChange?: (value: string) => void;
  className?: string;
  layoutId?: string;
  name?: string;
  "aria-label"?: string;
  "aria-labelledby"?: string;
}

type BaseRadioRootRenderProps =
  React.ButtonHTMLAttributes<HTMLButtonElement> & {
    className?: string;
    ref?: React.Ref<HTMLButtonElement>;
  };

type RadioOptionContentProps = {
  description?: string;
  descriptionId?: string;
  isSelected: boolean;
  label: string;
  labelId: string;
  layoutId: string;
  reduceMotion: boolean;
};

type BaseRadioOptionButtonProps = RadioOptionContentProps & {
  index: number;
  reduceMotion: boolean;
  rootProps: BaseRadioRootRenderProps;
};

function RadioOptionContent({
  description,
  descriptionId,
  isSelected,
  label,
  labelId,
  layoutId,
  reduceMotion,
}: RadioOptionContentProps) {
  const highlightTransition = getHighlightTransition(reduceMotion);
  const ringTransition = getRingTransition(reduceMotion);
  const dotMotion = getDotMotion(reduceMotion);
  const textTransition = getTextTransition(reduceMotion);

  return (
    <>
      {isSelected ? (
        <motion.div
          aria-hidden
          className="absolute inset-0 rounded-lg bg-foreground/[0.04]"
          layoutId={reduceMotion ? undefined : layoutId}
          transition={highlightTransition}
        />
      ) : null}

      <div
        aria-hidden
        className="relative z-10 flex h-5 w-5 shrink-0 items-center justify-center"
      >
        <motion.div
          animate={{
            borderWidth: isSelected ? 6 : 2,
            borderColor: isSelected
              ? "var(--primary)"
              : "color-mix(in srgb, var(--muted-foreground) 25%, transparent)",
          }}
          className="absolute inset-0 rounded-full"
          style={{ borderStyle: "solid" }}
          transition={ringTransition}
        />

        <AnimatePresence>
          {isSelected ? (
            <motion.div
              animate={dotMotion.animate}
              className="absolute h-1.5 w-1.5 rounded-full bg-background"
              exit={dotMotion.exit}
              initial={dotMotion.initial}
              transition={dotMotion.transition}
            />
          ) : null}
        </AnimatePresence>
      </div>

      <div className="relative z-10 flex flex-col gap-0.5">
        <motion.span
          animate={{
            color: isSelected ? "var(--foreground)" : "var(--muted-foreground)",
            fontWeight: isSelected ? 500 : 400,
          }}
          className="text-[14px] leading-tight"
          id={labelId}
          transition={textTransition}
        >
          {label}
        </motion.span>

        {description ? (
          <motion.span
            animate={{ opacity: isSelected ? 0.85 : 0.5 }}
            className="text-muted-foreground/60 text-xs leading-snug"
            id={descriptionId}
            transition={textTransition}
          >
            {description}
          </motion.span>
        ) : null}
      </div>
    </>
  );
}

function BaseRadioOptionButton({
  description,
  descriptionId,
  index,
  isSelected,
  label,
  labelId,
  layoutId,
  reduceMotion,
  rootProps,
}: BaseRadioOptionButtonProps) {
  const {
    className: rootClassName,
    onAnimationEnd: _onAnimationEnd,
    onAnimationIteration: _onAnimationIteration,
    onAnimationStart: _onAnimationStart,
    onDrag: _onDrag,
    onDragEnd: _onDragEnd,
    onDragEnter: _onDragEnter,
    onDragExit: _onDragExit,
    onDragLeave: _onDragLeave,
    onDragOver: _onDragOver,
    onDragStart: _onDragStart,
    onDrop: _onDrop,
    ref: rootRef,
    ...resolvedRootProps
  } = rootProps;

  return (
    <motion.button
      {...resolvedRootProps}
      animate={reduceMotion ? undefined : { opacity: 1, y: 0 }}
      className={cn(
        "relative flex w-full touch-manipulation select-none items-center gap-3.5 rounded-lg px-4 py-3.5 text-left outline-none focus-visible:ring-2 focus-visible:ring-ring",
        rootClassName
      )}
      initial={reduceMotion ? false : { opacity: 0, y: 8 }}
      ref={(node) => {
        setRef(rootRef, node);
      }}
      transition={
        reduceMotion
          ? reducedTransition
          : { delay: index * 0.05, duration: 0.3 }
      }
      type="button"
      whileHover={reduceMotion ? undefined : { x: 2 }}
      whileTap={reduceMotion ? undefined : { scale: 0.98 }}
    >
      <RadioOptionContent
        description={description}
        descriptionId={descriptionId}
        isSelected={isSelected}
        label={label}
        labelId={labelId}
        layoutId={layoutId}
        reduceMotion={reduceMotion}
      />
    </motion.button>
  );
}

const RadioGroup = React.forwardRef<HTMLDivElement, RadioGroupProps>(
  (
    {
      "aria-label": ariaLabel,
      "aria-labelledby": ariaLabelledBy,
      className,
      defaultValue,
      layoutId,
      name,
      onChange,
      options,
      reducedMotion,
      value,
    },
    ref
  ) => {
    const generatedId = React.useId();
    const isControlled = value !== undefined;
    const [uncontrolledSelected, setUncontrolledSelected] = React.useState<
      string | undefined
    >(() => getValidSelection(options, defaultValue));
    const selected = isControlled ? value : uncontrolledSelected;
    const resolvedLayoutId = layoutId ?? `radio-active-bg-${generatedId}`;
    const groupName = name ?? `radio-group-${generatedId}`;
    const reduceMotion = useResolvedReducedMotion(reducedMotion);

    React.useEffect(() => {
      if (isControlled) {
        return;
      }

      const normalized = getValidSelection(options, uncontrolledSelected);

      if (normalized !== uncontrolledSelected) {
        setUncontrolledSelected(normalized);
      }
    }, [isControlled, options, uncontrolledSelected]);

    const handleSelect = React.useCallback(
      (nextValue: string) => {
        if (nextValue === selected) {
          return;
        }

        if (!isControlled) {
          setUncontrolledSelected(nextValue);
        }

        onChange?.(nextValue);
      },
      [isControlled, onChange, selected]
    );

    if (options.length === 0) {
      return null;
    }

    return (
      <ReducedMotionConfig reducedMotion={reducedMotion}>
        <RadioGroupPrimitive
          aria-label={ariaLabel}
          aria-labelledby={ariaLabelledBy}
          className={cn(registryTheme, "flex flex-col gap-0.5", className)}
          name={groupName}
          onValueChange={handleSelect}
          ref={ref}
          value={selected}
        >
          {options.map((option, index) => {
            const isSelected = selected === option.value;
            const optionId = `${generatedId}-option-${index}`;
            const labelId = `${optionId}-label`;
            const descriptionId = option.description
              ? `${optionId}-description`
              : undefined;

            return (
              <RadioPrimitive.Root
                aria-describedby={descriptionId}
                aria-labelledby={labelId}
                key={option.value}
                nativeButton
                render={(rootProps) => (
                  <BaseRadioOptionButton
                    description={option.description}
                    descriptionId={descriptionId}
                    index={index}
                    isSelected={isSelected}
                    label={option.label}
                    labelId={labelId}
                    layoutId={resolvedLayoutId}
                    reduceMotion={reduceMotion}
                    rootProps={rootProps}
                  />
                )}
                value={option.value}
              />
            );
          })}
        </RadioGroupPrimitive>
      </ReducedMotionConfig>
    );
  }
);

RadioGroup.displayName = "RadioGroup";

export { RadioGroup as radioGroup };
export { RadioGroup };
export default RadioGroup;
